      await notificationService.sendNotification({
        type: 'welcome',
        recipient: 'user-1',
        subject: 'Welcome',
        body: 'Hello!',
        channel: 'email',
        metadata: { userId: 'user-1' },
      });

      await notificationService.sendNotification({
        type: 'welcome',
        recipient: 'user-1',
        subject: 'Welcome',
        body: 'Hello!',
        channel: 'sms',
        metadata: { userId: 'user-1' },
      });

      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });

    it('delivers to user with no explicit preferences (defaults)', async () => {
