  // ==========================================
  // Notification ordering
  // ==========================================

  describe('Notification ordering', () => {
    it('preserves delivery order for the same recipient', async () => {
      const { notificationService, historyService, preferencesService } = pipeline;

      // Use email channel (enabled by default) and send multiple notifications
      const sendOrder: string[] = [];
      const subjects = ['First', 'Second', 'Third'];

      for (const subject of subjects) {
        await notificationService.sendNotification({
          type: 'order_confirmation',
          recipient: 'alice@example.com',
          subject,
          body: `Notification: ${subject}`,
          channel: 'email',
          metadata: { userId: 'user-1' },
        });
        sendOrder.push(subject);
      }

      const history = historyService.getAll();
      expect(history).toHaveLength(3);
      expect(history[0].subject).toBe('First');
      expect(history[1].subject).toBe('Second');
      expect(history[2].subject).toBe('Third');
    });

    it('allows concurrent delivery for different recipients', async () => {
      const { notificationService, historyService } = pipeline;

      // Fire off notifications to two different recipients concurrently
      await Promise.all([
        notificationService.sendNotification({
          type: 'welcome',
          recipient: 'alice@example.com',
          subject: 'Welcome Alice',
          body: 'Hello Alice!',
          channel: 'email',
          metadata: { userId: 'user-1' },
        }),
        notificationService.sendNotification({
          type: 'welcome',
          recipient: 'bob@example.com',
          subject: 'Welcome Bob',
          body: 'Hello Bob!',
          channel: 'email',
          metadata: { userId: 'user-2' },
        }),
      ]);

      const history = historyService.getAll();
      expect(history).toHaveLength(2);

      const recipients = history.map((e) => e.recipient);
      expect(recipients).toContain('alice@example.com');
      expect(recipients).toContain('bob@example.com');
    });
  });

  // ==========================================
  // Multi-channel scenarios
  // ==========================================

  describe('Multi-channel delivery', () => {
    it('sends same notification type through multiple enabled channels', async () => {
      const { notificationService, emailAdapter, smsAdapter, webhookTransport, preferencesService, historyService } = pipeline;

      // Enable all channels
      preferencesService.updatePreferences('user-1', {
        channelPreferences: {
          email: { enabled: true },
          sms: { enabled: true },
          webhook: { enabled: true },
        },
      });

      const basePayload = {
        type: 'order_confirmation' as const,
        recipient: 'user-1',
        subject: 'Order #42 Confirmed',
        body: 'Your order has been confirmed.',
        metadata: { userId: 'user-1', orderId: 'order-42' },
      };

      // Send through all three channels
      await notificationService.sendNotification({ ...basePayload, channel: 'email' });
      await notificationService.sendNotification({ ...basePayload, channel: 'sms' });
      await notificationService.sendNotification({ ...basePayload, channel: 'webhook' });

      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
      expect(webhookTransport.getDeliveries()).toHaveLength(1);

      const history = historyService.getAll();
      expect(history).toHaveLength(3);
      expect(history.every((e) => e.status === 'sent')).toBe(true);
    });

    it('full event-driven flow: order created triggers email, then manual SMS and webhook', async () => {
      const { eventBus, notificationService, emailAdapter, smsAdapter, webhookTransport, preferencesService, historyService } = pipeline;

      const user = createTestUser();
      const order = createTestOrder();

      // Enable all channels
      preferencesService.updatePreferences(user.id, {
        channelPreferences: {
          sms: { enabled: true },
          webhook: { enabled: true },
        },
      });

      // Step 1: EventBus triggers email automatically
      await eventBus.emit<OrderCreatedEvent>({
        type: 'order:created',
        order,
        user,
        timestamp: new Date(),
      });

      expect(emailAdapter.getSentEmails()).toHaveLength(1);

      // Step 2: Application sends SMS and webhook for the same event
      await notificationService.sendNotification({
        type: 'order_confirmation',
        recipient: user.id,
        subject: `Order Confirmation: ${order.id}`,
        body: `Your order has been placed. Total: $${order.total.toFixed(2)}`,
        channel: 'sms',
        metadata: { userId: user.id },
